// Extraire le brief SEO de la réponse OpenAI
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';
const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let brief;
try {
  brief = JSON.parse(cleaned);
} catch (e) {
  // Fallback si le JSON est malformé
  const trendData = $('Préparer les données').first().json;
  brief = {
    keyword_primary: trendData.question.split(':')[0].trim().toLowerCase(),
    keywords_secondary: [trendData.source, 'paie 2026', 'obligations employeur'],
    icp_target: trendData.icp_target || 'ICP 1+2',
    title_suggestion: trendData.question,
    angle: 'Guide pratique pour employeurs',
    outline: ['Définition', 'Obligations', 'Impact paie', 'FAQ'],
    sources_to_cite: [trendData.source],
    estimated_word_count: 1000
  };
}

// Garder le trend_id pour le lier à l'article
const trendData = $('Préparer les données').first().json;
brief.trend_id = trendData.trend_id;

return [{ json: brief }];

// Résumé final de l'exécution
const brief = $('Parser le Brief').first().json;
const articleResponse = $input.first().json;

const result = {
  status: articleResponse.success ? 'SUCCESS' : 'FAILED',
  keyword: brief.keyword_primary,
  article_title: articleResponse.article?.title || 'N/A',
  article_slug: articleResponse.article?.slug || 'N/A',
  article_id: articleResponse.article?.id || 'N/A',
  word_count: articleResponse.article?.word_count || 0,
  brief_generated: {
    title_suggestion: brief.title_suggestion,
    keywords_secondary: brief.keywords_secondary,
    angle: brief.angle
  },
  message: articleResponse.success 
    ? `Article généré avec succès : ${articleResponse.article?.title} (${articleResponse.article?.word_count} mots)`
    : `Erreur : ${articleResponse.error || 'Unknown error'}`
};

return [{ json: result }];
